// // This module selects the least significant bit of the input based on the select signal
module mux_4to1(
	input [7:0] a,
	input [7:0] b,
	input [7:0] c,
	input [7:0] d,
	input [1:0] sel,
	output [7:0] y
);

	assign y = (sel == 2'b00) ? a : 
	           (sel == 2'b01) ? b : 
	           (sel == 2'b10) ? c : d;

endmodule
